import { createContext, type MouseEvent as ReactMouseEvent } from 'react';

import { TooltipItem } from '../../../../types/tooltip.js';

/**
 * Context which contains rendering and general handlers for the shared interactive
 * tooltip.
 */
export type InteractiveTooltipContextProps = {
  selectItem: (event: ReactMouseEvent, series?: TooltipItem) => void;
  selectedItem?: TooltipItem;
  hasScrollbar: boolean;
  setHasScrollbar: (v: boolean) => void;
};

export const InteractiveTooltipContext =
  createContext<InteractiveTooltipContextProps>(
    {} as InteractiveTooltipContextProps,
  );
